// Parse the inbound email and extract structured signals
const emailItem = $input.first();
const email = emailItem.json;
const binary = emailItem.binary || {};

// Sender details
const fromHeader = email.from?.value?.[0] || {};
const applicantEmail = fromHeader.address || email.from?.text || email.From || 'unknown@unknown.com';
const applicantName = fromHeader.name || (typeof applicantEmail === 'string' ? applicantEmail.split('@')[0] : 'there');

// Combine subject + body for URL extraction
const subject = email.subject || '';
const bodyText = email.text || email.textPlain || email.snippet || '';
const bodyHtml = email.html || email.textHtml || '';
const combinedText = `${subject}\n${bodyText}\n${bodyHtml}`;

// Extract GitHub URL/username
const githubRegex = /(?:https?:\/\/)?(?:www\.)?github\.com\/([a-zA-Z0-9](?:[a-zA-Z0-9-]{0,38}[a-zA-Z0-9])?)/i;
const githubMatch = combinedText.match(githubRegex);
const githubUsername = githubMatch ? githubMatch[1] : null;
const githubUrl = githubMatch ? `https://github.com/${githubUsername}` : null;

// Extract any URLs
const urlRegex = /https?:\/\/[^\s<>"')]+/gi;
const allUrls = [...new Set((combinedText.match(urlRegex) || []).map(u => u.replace(/[.,;:!?)\]]+$/, '')))];

// Excluded domains for portfolio detection
const NON_PORTFOLIO_DOMAINS = [
  'github.com', 'gitlab.com', 'bitbucket.org',
  'linkedin.com', 'lnkd.in',
  'twitter.com', 'x.com', 'facebook.com', 'instagram.com',
  'youtube.com', 'youtu.be',
  'docs.google.com', 'drive.google.com', 'dropbox.com',
  'mailto:', 'unsubscribe', 'sendgrid.net', 'mailgun.org', 'list-manage.com',
  'wa.me', 't.me'
];

const portfolioCandidates = allUrls.filter(u => {
  const lower = u.toLowerCase();
  return !NON_PORTFOLIO_DOMAINS.some(domain => lower.includes(domain));
});
const portfolioUrl = portfolioCandidates[0] || null;

const linkedinUrl = allUrls.find(u =>
  u.toLowerCase().includes('linkedin.com') || u.toLowerCase().includes('lnkd.in')
) || null;

// Detect PDF resume from binary data
const binaryKeys = Object.keys(binary);
let pdfBinaryKey = null;
let pdfFilename = null;
for (const key of binaryKeys) {
  const att = binary[key];
  const fname = (att.fileName || att.filename || '').toLowerCase();
  const mime = (att.mimeType || att.contentType || '').toLowerCase();
  if (fname.endsWith('.pdf') || mime.includes('pdf')) {
    pdfBinaryKey = key;
    pdfFilename = att.fileName || att.filename;
    break;
  }
}
const hasResumeAttachment = pdfBinaryKey !== null;

// Auto-reply / OOO detection
const headers = email.headers || {};
const autoSubmitted = headers['auto-submitted'] || headers['Auto-Submitted'] || '';
const isAutoReply = (autoSubmitted && autoSubmitted.toLowerCase() !== 'no')
  || subject.toLowerCase().includes('out of office')
  || subject.toLowerCase().includes('automatic reply')
  || applicantEmail.toLowerCase().startsWith('mailer-daemon@')
  || applicantEmail.toLowerCase().startsWith('postmaster@');

// Follow-up detection: if subject starts with "Re:", "Fwd:", or this is a reply to an existing thread
// Gmail prefixes replies with "Re:" by default — that's our signal that this is a reply
const isFollowUp = (
  subject.toLowerCase().startsWith('re:') ||
  subject.toLowerCase().startsWith('fwd:') ||
  subject.toLowerCase().startsWith('fw:')
);

return [{
  json: {
    applicantEmail,
    applicantName,
    subject,
    bodyText: bodyText.slice(0, 5000),
    githubUsername,
    githubUrl,
    portfolioUrl,
    linkedinUrl,
    hasResumeAttachment,
    pdfBinaryKey,
    pdfFilename,
    binaryKeys,
    isAutoReply,
    isFollowUp,
    messageId: email.messageId || email.id || null,
    threadId: email.threadId || null,
    receivedAt: new Date().toISOString()
  },
  binary: binary
}];

// Build the evaluation context for Claude — reads directly from upstream nodes
const parsed = $('Parse Email & Extract Signals').first().json;

// Resume text from extraction
let resumeText = '';
try {
  const extractItem = $('Extract Resume Text').first();
  resumeText = (extractItem?.json?.text || extractItem?.json?.data || '').slice(0, 12000);
} catch (e) {
  resumeText = '[Resume text could not be extracted]';
}

// Drive link
let resumeDriveLink = '';
try {
  const driveItem = $('Upload Resume to Drive').first();
  if (driveItem?.json?.webViewLink) resumeDriveLink = driveItem.json.webViewLink;
  else if (driveItem?.json?.id) resumeDriveLink = `https://drive.google.com/file/d/${driveItem.json.id}/view`;
} catch (e) {
  resumeDriveLink = '';
}

// GitHub profile
let profileSummary;
try {
  const githubProfileItem = $('Fetch GitHub Profile').first();
  const profile = githubProfileItem?.json || {};
  if (profile && !profile.message && profile.login) {
    profileSummary = {
      username: profile.login,
      name: profile.name || '',
      bio: profile.bio || '',
      publicRepos: profile.public_repos || 0,
      followers: profile.followers || 0,
      accountCreated: profile.created_at || null,
      company: profile.company || '',
      blog: profile.blog || ''
    };
  } else {
    profileSummary = { error: profile.message || 'Could not fetch GitHub profile' };
  }
} catch (e) {
  profileSummary = { error: `GitHub profile fetch failed: ${e.message}` };
}

// GitHub repos
let repoSummary = [];
let languageCounts = {};
try {
  const reposItem = $('Fetch GitHub Repos').first();
  const repos = Array.isArray(reposItem?.json) ? reposItem.json : [];
  repoSummary = repos.slice(0, 12).map(r => ({
    name: r.name,
    description: r.description,
    language: r.language,
    stars: r.stargazers_count,
    forks: r.forks_count,
    updated: r.updated_at,
    isFork: r.fork
  }));
  repos.forEach(r => {
    if (r.language) languageCounts[r.language] = (languageCounts[r.language] || 0) + 1;
  });
} catch (e) {
  repoSummary = [];
  languageCounts = {};
}


// Portfolio content (fetched and parsed from applicant's website)
let portfolioContent = '';
try {
  const portfolioItem = $('Parse Portfolio Content').first();
  portfolioContent = (portfolioItem?.json?.text || '').slice(0, 5000);
} catch (e) {
  portfolioContent = ''; // Not fetched — no portfolio URL or fetch skipped
}
// Evaluation flags (which signals are missing/reduced)
const evaluationFlags = {
  reducedConfidenceOn: [],
  notes: []
};
const hasGithub = parsed.githubUrl !== null;
const hasPortfolio = parsed.portfolioUrl !== null;
if (hasGithub && !hasPortfolio) {
  evaluationFlags.reducedConfidenceOn.push('business_thinking');
  evaluationFlags.notes.push('Portfolio not provided; business thinking evaluated from resume + GitHub only.');
}
if (hasPortfolio && !hasGithub) {
  evaluationFlags.reducedConfidenceOn.push('technical_depth', 'shipped_production_products');
  evaluationFlags.notes.push('GitHub not provided; technical and production-shipping signals evaluated from resume + portfolio only.');
}

return [{
  json: {
    applicantEmail: parsed.applicantEmail,
    applicantName: parsed.applicantName,
    githubUsername: parsed.githubUsername,
    githubUrl: parsed.githubUrl,
    portfolioUrl: parsed.portfolioUrl,
    linkedinUrl: parsed.linkedinUrl,
    receivedAt: parsed.receivedAt,
    resumeText,
    resumeDriveLink,
    githubProfile: profileSummary,
    githubRepos: repoSummary,
    githubLanguages: languageCounts,
    githubFetchOk: !profileSummary.error,
    portfolioContent,
    evaluationFlags
  }
}];

// Parse Claude's response and apply follow-up penalty if applicable
const applicantCtx = $('Build Evaluation Context').first().json;
const parsedEmail = $('Parse Email & Extract Signals').first().json;
const claudeResponse = $input.first().json;

let evaluation;
try {
  const text = claudeResponse?.content?.[0]?.text || '';
  const cleaned = text.replace(/```json\s*/i, '').replace(/```\s*$/i, '').trim();
  evaluation = JSON.parse(cleaned);
} catch (err) {
  evaluation = {
    scores: { shipped_production_products: 0, business_thinking: 0, technical_depth: 0, speed_of_execution: 0 },
    score_rationale: { shipped_production_products: 'Parse error', business_thinking: 'Parse error', technical_depth: 'Parse error', speed_of_execution: 'Parse error' },
    weighted_score: 0,
    decision: 'FAIL',
    confidence: 0,
    strengths: [],
    concerns: ['Evaluation could not be parsed'],
    inconsistencies: [`Parse error: ${err.message}`],
    specific_rejection_reason: 'There was a technical issue evaluating your application. Please feel free to resubmit and we will review again.',
    hiring_team_notes: 'AUTOMATED FAIL: Claude response could not be parsed as JSON.',
    parseError: err.message,
    rawResponse: claudeResponse?.content?.[0]?.text || JSON.stringify(claudeResponse)
  };
}

// Follow-up penalty: -0.5 if this submission was a reply to a missing-info reminder
if (parsedEmail.isFollowUp) {
  const originalScore = evaluation.weighted_score;
  evaluation.weighted_score = Math.max(1.0, parseFloat((evaluation.weighted_score - 0.5).toFixed(2)));
  evaluation.hiring_team_notes = (evaluation.hiring_team_notes || '') + 
    ` [Follow-up penalty: -0.5 applied (original: ${originalScore}). Applicant required a reminder for missing materials.]`;
}

// Confidence-based gate: override PASS to FAIL if confidence < 0.6
if (evaluation.decision === 'PASS' && (evaluation.confidence || 0) < 0.6) {
  evaluation.decision = 'FAIL';
  evaluation.specific_rejection_reason = evaluation.specific_rejection_reason || 'Based on the materials provided, we did not have enough confidence to advance the application. We encourage you to apply again with additional examples of shipped work or relevant projects.';
  evaluation.hiring_team_notes = (evaluation.hiring_team_notes || '') + ' [Auto-overridden from PASS to FAIL: confidence below 0.6 threshold.]';
}

// Re-evaluate decision after follow-up penalty (might have dropped below 3.5)
if (evaluation.decision === 'PASS' && evaluation.weighted_score < 3.5) {
  evaluation.decision = 'FAIL';
  evaluation.hiring_team_notes = (evaluation.hiring_team_notes || '') + ' [Re-classified as FAIL after follow-up penalty dropped weighted_score below 3.5 threshold.]';
}

const confidencePct = Math.round((evaluation.confidence || 0) * 100);
const strengthsStr = (evaluation.strengths || []).join(' | ');
const concernsStr = (evaluation.concerns || []).join(' | ');
const inconsistenciesStr = (evaluation.inconsistencies || []).join(' | ');
const combinedConcerns = [concernsStr, inconsistenciesStr].filter(Boolean).join(' || ');

return [{
  json: {
    applicantEmail: applicantCtx.applicantEmail,
    applicantName: applicantCtx.applicantName,
    githubUrl: applicantCtx.githubUrl,
    portfolioUrl: applicantCtx.portfolioUrl,
    resumeDriveLink: applicantCtx.resumeDriveLink,
    evaluation,
    confidencePct,
    confidenceDisplay: `${confidencePct}%`,
    strengthsStr,
    concernsStr,
    inconsistenciesStr,
    combinedConcerns,
    isFollowUp: parsedEmail.isFollowUp,
    evaluatedAt: new Date().toISOString()
  }
}];

// Prepare the rejection feedback paragraph request
const data = $input.first().json;
const evaluation = data.evaluation;

const rejectionPrompt = `You are writing the feedback paragraph for a rejection email to a job applicant on behalf of the hiring team. The email wrapper, greeting, and closing are already templated; your job is to write only the specific feedback content.

Constraints:
- 2-3 sentences total
- Reference one specific concrete thing from their materials (a project, a claim, a repo) — not generic
- Use "we" throughout — never "I" or "the AI" or any first-person singular
- Respectful and direct, not corporate-fake-warm
- Frame as a fit gap, not a deficiency in the candidate
- Plain prose, no bullet points, no greeting, no signature, no signoff

The paragraph should:
- State the specific gap or signal that drove the decision
- Ground it in evidence from their actual application
- Avoid generic recruiter language

What to avoid:
- "We've decided to move forward with other candidates"
- "While your background is impressive..."
- "Best of luck in your future endeavors"
- First-person singular ("I noticed", "I reviewed")
- Mentioning AI, automated systems, or screening tools
- Apologizing or hedging excessively

Input data:

Candidate name: ${data.applicantName || 'the candidate'}
Specific rejection reason: ${evaluation.specific_rejection_reason || ''}
Concerns: ${JSON.stringify(evaluation.concerns || [])}
Inconsistencies: ${JSON.stringify(evaluation.inconsistencies || [])}

Return ONLY the feedback paragraph text. No greeting, no closing, no signature.`;

const requestBody = {
  model: "claude-sonnet-4-5",
  max_tokens: 500,
  messages: [
    {
      role: "user",
      content: rejectionPrompt
    }
  ]
};

return [{
  json: {
    ...data,
    rejectionRequestBody: JSON.stringify(requestBody)
  }
}];

// Parse the rejection feedback response
const priorData = $('Parse Evaluation').first().json;
const claudeResponse = $input.first().json;

let feedbackParagraph;
try {
  feedbackParagraph = (claudeResponse?.content?.[0]?.text || '').trim();
  if (!feedbackParagraph) {
    feedbackParagraph = priorData.evaluation?.specific_rejection_reason 
      || 'After reviewing your application, we have decided not to move forward at this time.';
  }
} catch (err) {
  feedbackParagraph = priorData.evaluation?.specific_rejection_reason 
    || 'After reviewing your application, we have decided not to move forward at this time.';
}

return [{
  json: {
    ...priorData,
    rejectionFeedback: feedbackParagraph
  }
}];

// Build the log entry for a duplicate skip — matches error-handler format
const applicantEmail = $('Parse Email & Extract Signals').first().json.applicantEmail;
const applicantName = $('Parse Email & Extract Signals').first().json.applicantName;
const subject = $('Parse Email & Extract Signals').first().json.subject;
const timestamp = new Date().toISOString();

const logEntry = [
  '=' .repeat(70),
  `${timestamp} | DUPLICATE SKIPPED in Plum Candidate Evaluator`,
  '=' .repeat(70),
  `Applicant:    ${applicantName} <${applicantEmail}>`,
  `Subject:      ${subject}`,
  `Reason:       Previously evaluated — silently skipped`,
  '\n'
].join('\n');

return [{
  json: {
    status: 'skipped',
    reason: 'duplicate — applicant previously evaluated',
    applicantEmail,
    applicantName,
    subject,
    timestamp,
    logEntry
  }
}];

// Re-attach the PDF binary from the Parse Email node onto the current item
// so that Upload Resume to Drive and Extract Resume Text can access it.
const parseItem = $('Parse Email & Extract Signals').first();
const pdfKey = parseItem.json.pdfBinaryKey;

if (!pdfKey || !parseItem.binary || !parseItem.binary[pdfKey]) {
  throw new Error('PDF binary not found on Parse Email node. Key: ' + pdfKey);
}

return [{
  json: { ...parseItem.json },
  binary: {
    [pdfKey]: parseItem.binary[pdfKey]
  }
}];

const item = $input.first();
const raw = item.json?.data || item.json?.body || '';

let text = raw.trim().slice(0, 6000);

const portfolioUrl = $('Parse Email & Extract Signals').item.json.portfolioUrl;

if (!text || text.length < 50) {
  text = '[Portfolio page returned no readable content]';
}

return [{ json: { text, portfolioUrl, charCount: text.length } }];

// Compose the missing-info reply based on which signals are present.
// Three cases:
//   A) Resume present, link missing
//   B) Link present, resume missing
//   C) Both missing

const sig = $('Parse Email & Extract Signals').item.json;
const firstName = (sig.applicantName || '').split(' ')[0] || 'there';

const hasResume = !!sig.hasResumeAttachment;
const hasLink = sig.githubUrl !== null || sig.portfolioUrl !== null;

let body;

if (hasResume && !hasLink) {
  // Case A
  body =
`<p>Hi ${firstName},</p>

<p>Thanks for applying to the AI Builder role at Plum &mdash; we received your resume.</p>

<p>To complete your application, we still need a <b>GitHub profile link or a portfolio/project link</b> (either one is fine, both is great).</p>

<p>Could you reply on this same thread with your complete application &mdash; please re-attach your resume and include the link(s) in the email?</p>

<p>Looking forward to it.</p>

<p>Best,<br>The Plum Recruitment Team</p>`;
} else if (!hasResume && hasLink) {
  // Case B
  body =
`<p>Hi ${firstName},</p>

<p>Thanks for applying to the AI Builder role at Plum &mdash; we received your link(s).</p>

<p>To complete your application, we still need a <b>PDF resume attachment</b>.</p>

<p>Could you reply on this same thread with your complete application &mdash; please attach your resume and include your GitHub and/or portfolio link in the email?</p>

<p>Looking forward to it.</p>

<p>Best,<br>The Plum Recruitment Team</p>`;
} else {
  // Case C: nothing present (or unexpected — covers the "neither" case)
  body =
`<p>Hi ${firstName},</p>

<p>Thanks for reaching out about the AI Builder role at Plum.</p>

<p>To evaluate your application, we'll need:</p>

<ul>
  <li>A <b>PDF resume</b> attached to the email</li>
  <li>A <b>GitHub profile link or portfolio link</b> (at least one)</li>
</ul>

<p>Could you reply on this same thread with both?</p>

<p>Looking forward to it.</p>

<p>Best,<br>The Plum Recruitment Team</p>`;
}

return [{
  json: {
    replySubject: 'Re: Application for AI Builder \u2014 additional details needed',
    replyBody: body,
    case: hasResume && !hasLink ? 'A_resume_only'
        : !hasResume && hasLink ? 'B_link_only'
        : 'C_nothing'
  }
}];
